import java.util.*;
public class ValidParen {
    public static boolean isValid(String s) {
        Deque<Character> stack = new ArrayDeque<>();
        for (char c : s.toCharArray()) {
            if (c=='('||c=='['||c=='{') stack.push(c);
            else if (stack.isEmpty()) return false;
            else if (c==')' && stack.pop()!='(') return false;
            else if (c==']' && stack.pop()!='[') return false;
            else if (c=='}' && stack.pop()!='{') return false;
        }
        return stack.isEmpty();
    }
    public static void main(String[] a){
        System.out.println(isValid("()[]{}"));   // true
        System.out.println(isValid("(]"));        // false
        System.out.println(isValid("{[()]}"));    // true
        System.out.println("O(n) time O(n) space");
    }
}

import java.util.*;
public class MinStackDemo {
    static class MinStack {
        Deque<Integer> stack=new ArrayDeque<>(), minStack=new ArrayDeque<>();
        void push(int v){stack.push(v);if(minStack.isEmpty()||v<=minStack.peek())minStack.push(v);}
        void pop(){if((int)stack.pop()==(int)minStack.peek())minStack.pop();}
        int top(){return stack.peek();}
        int getMin(){return minStack.peek();}
    }
    public static void main(String[] a){
        MinStack ms=new MinStack();
        ms.push(-2);ms.push(0);ms.push(-3);
        System.out.println(ms.getMin()); // -3
        ms.pop();
        System.out.println(ms.top());    // 0
        System.out.println(ms.getMin()); // -2
        System.out.println("O(1) all ops — two stacks");
    }
}

