import java.util.*;
public class DailyTemps {
    public static int[] dailyTemperatures(int[] T) {
        int n=T.length; int[] result=new int[n];
        Deque<Integer> stack=new ArrayDeque<>(); // indices
        for(int i=0;i<n;i++){
            while(!stack.isEmpty()&&T[i]>T[stack.peek()])
                result[stack.pop()]=i-stack.peek()-1+1; // fix: use i - popped
            stack.push(i);
        }
        // Fix: recalculate
        Arrays.fill(result,0);
        Deque<Integer> st=new ArrayDeque<>();
        for(int i=0;i<n;i++){
            while(!st.isEmpty()&&T[i]>T[st.peek()]){
                int idx=st.pop();
                result[idx]=i-idx;
            }
            st.push(i);
        }
        return result;
    }
    public static void main(String[] a){
        System.out.println(Arrays.toString(dailyTemperatures(new int[]{73,74,75,71,69,72,76,73})));
        System.out.println("O(n) — monotonic decreasing stack of indices");
    }
}

import java.util.*;
public class EvalRPN {
    public static int evalRPN(String[] tokens) {
        Deque<Integer> stack=new ArrayDeque<>();
        for(String t:tokens){
            if(t.equals("+")||t.equals("-")||t.equals("*")||t.equals("/")){
                int b=stack.pop(),a=stack.pop();
                if(t.equals("+"))stack.push(a+b);
                else if(t.equals("-"))stack.push(a-b);
                else if(t.equals("*"))stack.push(a*b);
                else stack.push(a/b);
            } else stack.push(Integer.parseInt(t));
        }
        return stack.pop();
    }
    public static void main(String[] a){
        System.out.println(evalRPN(new String[]{"2","1","+","3","*"})); // 9
        System.out.println(evalRPN(new String[]{"4","13","5","/","+"})); // 6
        System.out.println("O(n) stack-based RPN evaluation");
    }
}

import java.util.*;
public class RemoveDups {
    public static String removeDuplicates(String s) {
        Deque<Character> stack=new ArrayDeque<>();
        for(char c:s.toCharArray()){
            if(!stack.isEmpty()&&stack.peek()==c) stack.pop();
            else stack.push(c);
        }
        StringBuilder sb=new StringBuilder();
        while(!stack.isEmpty()) sb.append(stack.pop());
        return sb.reverse().toString();
    }
    public static void main(String[] a){
        System.out.println(removeDuplicates("abbaca")); // ca
        System.out.println(removeDuplicates("azxxzy")); // ay
        System.out.println("O(n) stack: pop on match, push on no-match");
    }
}

import java.util.*;
public class Asteroids {
    public static int[] asteroidCollision(int[] a) {
        Deque<Integer> stack=new ArrayDeque<>();
        for(int ast:a){
            boolean alive=true;
            while(alive&&ast<0&&!stack.isEmpty()&&stack.peek()>0){
                if(stack.peek()<-ast) stack.pop();
                else if(stack.peek()==-ast){stack.pop();alive=false;}
                else alive=false;
            }
            if(alive) stack.push(ast);
        }
        int[] res=new int[stack.size()];int i=stack.size()-1;
        for(int v:stack)res[i--]=v; return res;
    }
    public static void main(String[] a){
        System.out.println(Arrays.toString(asteroidCollision(new int[]{5,10,-5})));  // [5,10]
        System.out.println(Arrays.toString(asteroidCollision(new int[]{8,-8})));     // []
        System.out.println(Arrays.toString(asteroidCollision(new int[]{10,2,-5}))); // [10]
        System.out.println("O(n) stack — collision resolution");
    }
}

import java.util.*;
public class DecodeStr {
    public static String decodeString(String s) {
        Deque<Integer> counts=new ArrayDeque<>();
        Deque<StringBuilder> builders=new ArrayDeque<>();
        StringBuilder curr=new StringBuilder(); int k=0;
        for(char c:s.toCharArray()){
            if(Character.isDigit(c)) k=k*10+(c-'0');
            else if(c=='['){counts.push(k);builders.push(curr);curr=new StringBuilder();k=0;}
            else if(c==']'){
                StringBuilder tmp=curr; curr=builders.pop();
                int times=counts.pop();
                for(int i=0;i<times;i++) curr.append(tmp);
            } else curr.append(c);
        }
        return curr.toString();
    }
    public static void main(String[] a){
        System.out.println(decodeString("3[a]2[bc]"));     // aaabcbc
        System.out.println(decodeString("3[a2[c]]"));      // accaccacc
        System.out.println(decodeString("2[abc]3[cd]ef")); // abcabccdcdcdef
        System.out.println("O(n) nested stack: save count+sb on '[', restore on ']'");
    }
}

import java.util.*;
public class RemoveKDigits {
    public static String removeKdigits(String num, int k) {
        Deque<Character> stack=new ArrayDeque<>();
        for(char c:num.toCharArray()){
            while(k>0&&!stack.isEmpty()&&stack.peek()>c){stack.pop();k--;}
            stack.push(c);
        }
        while(k-->0) stack.pop(); // remove remaining from top
        // Build result, strip leading zeros:
        StringBuilder sb=new StringBuilder();
        boolean leadingZero=true;
        for(char c:stack) if(c!='0'||!leadingZero){sb.append(c);leadingZero=false;}
        return sb.length()==0?"0":sb.toString();
    }
    public static void main(String[] a){
        System.out.println(removeKdigits("1432219",3)); // 1219
        System.out.println(removeKdigits("10200",1));   // 200
        System.out.println(removeKdigits("10",2));      // 0
        System.out.println("O(n) monotonic increasing stack");
    }
}

import java.util.*;
public class Calc2 {
    public static int calculate(String s) {
        Deque<Integer> stack=new ArrayDeque<>();
        int num=0; char op='+';
        for(int i=0;i<s.length();i++){
            char c=s.charAt(i);
            if(Character.isDigit(c)) num=num*10+(c-'0');
            if((!Character.isDigit(c)&&c!=' ')||i==s.length()-1){
                if(op=='+') stack.push(num);
                else if(op=='-') stack.push(-num);
                else if(op=='*') stack.push(stack.pop()*num);
                else stack.push(stack.pop()/num);
                op=c; num=0;
            }
        }
        int res=0; while(!stack.isEmpty()) res+=stack.pop(); return res;
    }
    public static void main(String[] a){
        System.out.println(calculate("3+2*2"));  // 7
        System.out.println(calculate("3/2"));    // 1
        System.out.println(calculate("3+5/2"));  // 5
        System.out.println("O(n) — previous operator applied to current number");
    }
}

import java.util.*;
public class Histogram {
    public static int largestRectangleArea(int[] heights) {
        Deque<Integer> stack=new ArrayDeque<>();
        int maxArea=0, n=heights.length;
        for(int i=0;i<=n;i++){
            int h=(i==n)?0:heights[i];
            while(!stack.isEmpty()&&h<heights[stack.peek()]){
                int height=heights[stack.pop()];
                int width=stack.isEmpty()?i:i-stack.peek()-1;
                maxArea=Math.max(maxArea,height*width);
            }
            stack.push(i);
        }
        return maxArea;
    }
    public static void main(String[] a){
        System.out.println(largestRectangleArea(new int[]{2,1,5,6,2,3})); // 10
        System.out.println(largestRectangleArea(new int[]{2,4}));          // 4
        System.out.println("O(n) monotonic increasing stack");
        System.out.println("Virtual 0 at end flushes all remaining bars");
    }
}

import java.util.*;
public class TrapRain {
    public static int trap(int[] height) {
        int water=0,left=0,right=height.length-1,leftMax=0,rightMax=0;
        while(left<right){
            if(height[left]<height[right]){
                if(height[left]>=leftMax) leftMax=height[left];
                else water+=leftMax-height[left];
                left++;
            } else {
                if(height[right]>=rightMax) rightMax=height[right];
                else water+=rightMax-height[right];
                right--;
            }
        }
        return water;
    }
    public static void main(String[] a){
        System.out.println(trap(new int[]{0,1,0,2,1,0,1,3,2,1,2,1})); // 6
        System.out.println(trap(new int[]{4,2,0,3,2,5}));               // 9
        System.out.println("O(n) O(1) two-pointer (optimal over stack approach)");
    }
}

import java.util.*;
public class StackSynth {
    static boolean validParen(String s){Deque<Character> st=new ArrayDeque<>();for(char c:s.toCharArray()){if(c=='('||c=='['||c=='{')st.push(c);else if(st.isEmpty())return false;else if(c==')'&&st.pop()!='(')return false;else if(c==']'&&st.pop()!='[')return false;else if(c=='}'&&st.pop()!='{')return false;}return st.isEmpty();}
    static int calcRPN(String[] t){Deque<Integer> st=new ArrayDeque<>();for(String s:t){if("+-*/".contains(s)){int b=st.pop(),a=st.pop();if(s.equals("+"))st.push(a+b);else if(s.equals("-"))st.push(a-b);else if(s.equals("*"))st.push(a*b);else st.push(a/b);}else st.push(Integer.parseInt(s));}return st.pop();}
    static String decode(String s){Deque<Integer> c=new ArrayDeque<>();Deque<StringBuilder> b=new ArrayDeque<>();StringBuilder cur=new StringBuilder();int k=0;for(char ch:s.toCharArray()){if(Character.isDigit(ch))k=k*10+(ch-'0');else if(ch=='['){c.push(k);b.push(cur);cur=new StringBuilder();k=0;}else if(ch==']'){StringBuilder t=cur;cur=b.pop();int n=c.pop();for(int i=0;i<n;i++)cur.append(t);}else cur.append(ch);}return cur.toString();}
    public static void main(String[] a){
        System.out.println(validParen("(){[]}"));
        System.out.println(calcRPN(new String[]{"2","1","+","3","*"}));
        System.out.println(decode("3[a2[c]]"));
