        System.out.println("All pass: "+ok);
    }
}

import java.util.*;
public class T1Final {
    static boolean valid(String s){Deque<Character> st=new ArrayDeque<>();for(char c:s.toCharArray()){if("([{".indexOf(c)>=0)st.push(c);else{if(st.isEmpty())return false;char top=st.pop();if(c==')'&&top!='(')return false;if(c==']'&&top!='[')return false;if(c=='}'&&top!='{')return false;}}return st.isEmpty();}
    static int largestRect(int[] h){Deque<Integer> st=new ArrayDeque<>();int max=0,n=h.length;for(int i=0;i<=n;i++){int height=(i==n)?0:h[i];while(!st.isEmpty()&&height<h[st.peek()]){int hh=h[st.pop()];int w=st.isEmpty()?i:i-st.peek()-1;max=Math.max(max,hh*w);}st.push(i);}return max;}
    static int calcII(String s){Deque<Integer> st=new ArrayDeque<>();int num=0;char op='+';for(int i=0;i<s.length();i++){char c=s.charAt(i);if(Character.isDigit(c))num=num*10+(c-'0');if((!Character.isDigit(c)&&c!=' ')||i==s.length()-1){if(op=='+')st.push(num);else if(op=='-')st.push(-num);else if(op=='*')st.push(st.pop()*num);else st.push(st.pop()/num);op=c;num=0;}}int r=0;while(!st.isEmpty())r+=st.pop();return r;}
    public static void main(String[] a){
        System.out.println("valid="+valid("()[{}]"));
        System.out.println("histogram="+largestRect(new int[]{2,1,5,6,2,3}));
        System.out.println("calc="+calcII("3+2*2"));
        boolean ok=valid("()[{}]")&&largestRect(new int[]{2,1,5,6,2,3})==10&&calcII("3+2*2")==7;
        System.out.println("All pass: "+ok);
    }
}
